// This is how to start building a migration script.
// I need the makeRequest method, so include that:
module.exports = function (migration, { makeRequest }) {

    // Edit content type 'blogpost', add new field 'mainImage'.
    // Field 'mainImage' is a link to an asset, an image file.
    const blogpost = migration.editContentType('blogpost');
    blogpost
        .createField('mainImage')
        .name('📷 Main Image')
        .type('Link')
        .linkType('Asset')
        .validations([
            {
                'linkMimetypeGroup': ['image']
            }
        ]);

    // Next transform every entry of type 'blogpost'.
    // Use data from the existing field 'image' and insert into
    // the newly created field 'mainImage'.
    migration.transformEntries({
        contentType: 'blogpost',
        from: ['image'],
        to: ['mainImage'],
        transformEntryForLocale: async (from, currentLocale) => {

            // If the 'image' field of the 'blogpost' entry is empty, 
            // ignore the entry and skip to the next one.
            if (from.image === null 
                || typeof (from.image) === "undefined") {
                return;
            }

            // Console log is really, really useful to figure out
            // what the objects you are working with look like.
            // Try this for example:
            console.log('# from.image:');
            console.log(from.image);
            
            // The 'image' field contains a link to a content type
            // called 'image'. Get the id of that 'image' entry.
            const imageEntryId = from.image[currentLocale].sys.id;

            // I want to find the image asset in the linked 'image'
            // entry. To get that, I need to request it from the
            // Contentful API directly:
            const imageEntry = await makeRequest({
                method: 'GET',
                url: `/entries/${imageEntryId}`
            });

            // Better log some more to see what the 'image'
            // entry actually looks like:
            console.log('# imageEntry:');
            console.log(imageEntry);

            // Seems what I'm looking for is in the 'image' field
            // of the 'image' entry. Sorry for the lack of imagination
            // in naming fields and content types.
            console.log('# imageEntry.fields[\'image\']:');
            console.log(imageEntry.fields['image']);

            // Let's copy the image asset link from the 'image' field
            // in the 'image' entry back to the 'mainImage' field in
            // the 'blogpost' entry.
            
            // I'm also getting rid of localization for image assets,
            // which is why I'm only copying the image asset for the

current locale.
            return {
                mainImage: imageEntry.fields['image'][currentLocale]
            };
        }
    });

    // Disable the old field for now so editors will not see it.
    blogpost.editField('image').disabled(true)
}

public static class InMemoryDatabaseContextSetup
{
    public static IServiceCollection AddInMemoryDatabases(
        this IServiceCollection services)
    {
        services.AddDbContext<DefaultDbContext>(
            options => options
                .UseInMemoryDatabase("DefaultConnection"));
        return services;
    }
}

public static IServiceCollection AddDatabases(
    this IServiceCollection services, 
    IConfiguration configuration)
{
    services.AddDbContext<DefaultDbContext>(
        options => options
            .UseSqlServer(configuration
                .GetConnectionString("DefaultConnection")));
    return services;
}

